{"name":"CO2HighAndPresenceAirPurifierWarning","cron":"","period":0,"code":"if ((#CarbonDioxideSensor).carbondioxidesensor_carbondioxide >= 1200 and (#PresenceSensor).presencesensor_presence == "present") {
  (#AirPurifier).airpurifier_setairpurifiermode("high")
  (#Speaker).speaker_speak("Warning: High carbon dioxide concentration detected.")
}"}

{"name":"RainAndHighHumidityDehumidifierDrying","cron":"","period":0,"code":"if ((#RainSensor).rain == true and (#HumiditySensor).humiditysensor_humidity >= 80) {
  (#Dehumidifier).dehumidifier_setdehumidifiermode("drying")
  (#Speaker).speaker_speak("It's raining and himidity is high")
}"}

{"name":"OvenModeChangeWhenNoPresence","cron":"","period":0,"code":"if ((#Oven).oven_ovenmode == "heating" and (#PresenceSensor).presencesensor_presence != "present") {
  (#Oven).oven_setovenmode("warming")
  (#Speaker).mediaplayback_speak("The oven mode has been changed to warming.")
}"}

{"name":"SmokeAlertWithValveControl","cron":"","period":0,"code":"if ((#PresenceSensor #LivingRoom).presencesensor_presence == true and (#SmokeDetector #Kitchen).smokedetector_smoke == true) {
  (#Speaker #LivingRoom).speaker_speak("Smoke detected in the kitchen. Please evacuate immediately.")
  (#Valve #Kitchen).valve_close()
}"}

{"name":"Auto AirPurifier Mode on High CO2","cron":"","period":0,"code":"if ((#AirQualitySensor).airqualitysensor_carbondioxide >= 1000 and (#AirPurifier).airpurifier_airpurifiermode == "sleep") {
  (#AirPurifier).airpurifier_setairpurifiermode("auto")
  (#Speaker).speaker_speak("Switching the air purifier to auto mode")
}"}

{"name":"GardenLightOnAndAnnouncement","cron":"","period":0,"code":"if ((#LightSensor).lightsensor_brightness < 50 and (#Switch).switch_switch == false) {
  (#Switch).switch_on()
  (#Speaker).speaker_speak("The garden light is now on.")
}"}
